import { 菩薩坐身, 上臂常勢, 前臂 } from './pusa.js';
import { 羂索 } from '../bujian/sanmaya.js';
import { 側拳, 臂釧, 腕釧 } from '../bujian/index.js';
export const 金剛索尊 = (bi) => 菩薩坐身(bi, {
    臂(bi, 筆) {
        const { 骨, 細, 陰, 陽 } = 筆;
        骨(() => { 上臂常勢(筆, -1, 40.0); 上臂常勢(筆, 1, 40.2); });
        // 尊右：羂索之環執於體側（環先落，拳覆其交結）
        羂索(bi, -8.6, 34.2, 0.85);
        骨(() => 陽(() => 前臂(bi, 筆, [-13.7, 40.2], [-10.3, 39.4], { 寬根: 2.5, 寬梢: 1.9, 弓: 0.3, 肘帽: true })));
        側拳(bi, -8.6, 38.3, 2.05, 1.05);
        // 尊左：拳安腰上
        骨(() => 陰(() => 前臂(bi, 筆, [13.8, 40.3], [13.0, 45.2], { 寬根: 2.4, 寬梢: 1.8, 弓: -0.3, 肘帽: false })));
        側拳(bi, 12.8, 47.5, Math.PI / 2, 1.05, -1);
        // 嚴
        臂釧(bi, -1, 12.1, 14.5, 33.4);
        臂釧(bi, 1, 12.1, 14.5, 33.4);
        細(() => {
            腕釧(bi, [[-11.5, 39.0, -10.7, 39.7, -9.9, 40.4], [-11.1, 39.9, -10.3, 40.6, -9.5, 41.3]], [-10.6, 40.1]);
            腕釧(bi, [[11.9, 44.5, 13.0, 45.0, 14.1, 44.6], [11.8, 45.4, 12.9, 45.9, 14.0, 45.5]], [12.9, 45.4]);
        });
    },
});
